269	// Draw agent sprite (pixel character)
270	function drawAgentSprite(agent, screenX, screenY) {
271	  const typeClass = getAgentTypeClassLower(agent.type);
272	  const colors = {
273	    'general': { body: '#3c5aa6', accent: '#ffc400' },
274	    'explorer': { body: '#4caf50', accent: '#ff9800' },
275	    'architect': { body: '#9c27b0', accent: '#ce93d8' },
276	    'reviewer': { body: '#ff9800', accent: '#ff6d00' },
277	    'default': { body: '#1ba8b5', accent: '#80deea' }
278	  };
279	  const c = colors[typeClass] || colors.default;
280	
281	  // Pixel art character 4x4 grid (each block is 6px)
282	  const b = 6; // block size
283	  const ox = screenX + 18;
284	  const oy = screenY + 6;
285	
286	  // Hair/head
287	  ctx.fillStyle = c.body;
288	  ctx.fillRect(ox, oy, b * 3, b);
289	  // Face
290	  ctx.fillStyle = '#fdd8a5';
291	  ctx.fillRect(ox, oy + b, b * 3, b);
292	  // Eyes
293	  ctx.fillStyle = '#1a1a2e';
294	  ctx.fillRect(ox + b, oy + b + 1, 2, 3);
295	  ctx.fillRect(ox + b * 2, oy + b + 1, 2, 3);
296	  // Arms
297	  ctx.fillStyle = c.body;
298	  ctx.fillRect(ox - b, oy + b * 2, b, b);
299	  ctx.fillRect(ox + b * 2, oy + b * 2, b, b);
300	  // Accent (tie / badge)
301	  ctx.fillStyle = c.accent;
302	  ctx.fillRect(ox + b, oy + b * 2, b, b);
303	  // Legs
304	  ctx.fillRect(ox + 2, oy + b * 3, b, b);
305	  ctx.fillRect(ox + b * 2 - 2, oy + b * 3, b, b);
306	  // Shoes
307	  ctx.fillStyle = '#3a3a5e';
308	  ctx.fillRect(ox + 1, oy + b * 3 + 4, b, 4);
309	  ctx.fillRect(ox + b * 2 - 3, oy + b * 3 + 4, b, 4);
310	
311	  // Name tag
312	  ctx.fillStyle = '#2a2a4e';
313	  ctx.font = 'bold 7px "Press Start 2P", monospace';
