315	  const tagX = screenX + (TILE - nameWidth - 6) / 2;
316	  const tagY = screenY - 2;
317	  ctx.fillRect(tagX - 1, tagY - 1, nameWidth + 8, 9);
318	  ctx.fillStyle = '#ffc400';
319	  ctx.fillText(agent.name, tagX + 3, tagY + 6);
320	
321	  // Status dot
322	  ctx.fillStyle = '#4caf50';
323	  ctx.fillRect(screenX + TILE - 8, screenY - 2, 5, 5);
324	}
