617	// Click handler for canvas - click on agents to inspect
618	canvas.addEventListener('click', (e) => {
619	  const rect = canvas.getBoundingClientRect();
620	  const clickX = e.clientX - rect.left + camX;
621	  const clickY = e.clientY - rect.top + camY;
622	
623	  const agentPositions = getAgentPositions();
624	  for (const pos of agentPositions) {
625	    // Find the tile for the agent
626	    const tileX = pos.x;
627	    const tileY = pos.y;
628	    if (clickX >= tileX * TILE && clickX < (tileX + 1) * TILE &&
629	        clickY >= tileY * TILE && clickY < (tileY + 1) * TILE) {
630	      openAgentDetail(pos.agent.id);
631	      return;
632	    }
633	  }
634	
635	  // Check if clicking near an agent's name tag
636	  for (const pos of agentPositions) {
637	    const agentX = pos.x * TILE;
638	    const agentY = pos.y * TILE - 8;
639	    if (clickX >= agentX && clickX < agentX + TILE &&
640	        clickY >= agentY && clickY < agentY + TILE) {
641	      openAgentDetail(pos.agent.id);
642	      return;
643	    }
