706	// Auto-spawn agent via server
707	async function spawnAgent(name, role, prompt, description) {
708	  try {
709	    const response = await fetch(`${API_BASE}/api/spawn`, {
710	      method: 'POST',
711	      headers: { 'Content-Type': 'application/json' },
712	      body: JSON.stringify({ name, role, prompt, description })
713	    });
714	    const data = await response.json();
715	    if (data.success) {
716	      showNotification(`<strong>Agent "${name}" launched!</strong><br>A new Terminal window opened.<br>The agent will appear on the map when active.`, 8000);
717	      // Auto-refresh after a delay to pick up the new agent
718	      setTimeout(refreshData, 3000);
719	    } else {
